mapper.select:
SELECT t.*, ROW_NUMBER() OVER (ORDER BY t.location, t.itemcode, t.barcode) AS rn FROM ( SELECT l.sdate, l.factory, l.storage, l.location, l.barcode, l.itemcode, l.qty, i.spec as oitemcode, i.itemname, l.useyn, L.YMDHMS_D, B.CUSTCODE, (SELECT USEYN FROM T_WMS_LOCATION LL WHERE L.IID = LL.IID) AS useynnow, (SELECT memo_d FROM T_WMS_LOCATION LL WHERE L.IID = LL.IID) AS adjust, (SELECT DISTINCT 'Y' FROM T_WMS_REALSTOCK RR WHERE L.BARCODE = RR.BARCODE AND SDATE>=#{startdate}
AND SUBSTR(RR.YMDHMS, 9, 2) >= #{hour}
AND SUBSTR(RR.YMDHMS, 9, 2) <= #{hour}
) AS BARCODESCAN, nvl((SELECT distinct USEYN FROM T_WMS_LOCATION LL WHERE L.iid = LL.iid and useyn ='Y'),'N') AS useynbarcode -- 260427 이부장님과 이야기후 barcode에서 iid로 변경 FROM t_wms_locationBACKUP l LEFT JOIN t_wms_realstock r ON r.useyn = 'Y' AND r.barcode = l.barcode
AND SUBSTR(R.YMDHMS, 9, 2) >= #{hour}
AND SUBSTR(R.YMDHMS, 9, 2) <= #{hour}
left join t_mi_item i on i.itemcode = l.itemcode LEFT JOIN T_MI_ITEM_CUSTINFO B ON L.ITEMCODE = B.ITEMCODE WHERE 1 = 1
AND B.CUSTCODE = #{custcode}
AND r.location IS NULL ) t
where NOT ( -- ✅ COMPLETE 조건 전체를 부정 NVL(t.adjust, 'NORMAL') NOT IN ('ADJUSTMENT', 'LOADEXCEPTION-NOSCAN') AND ( NVL(t.useynbarcode,'Y') = 'N' OR NVL(t.barcodescan, 'N') = 'Y' ) )
where t.adjust = 'ADJUSTMENT' OR T.ADJUST = 'LOADEXCEPTION-NOSCAN'
where -- 1. ADJUST 쪽 먼저 제외 NVL(t.adjust, 'NORMAL') NOT IN ('ADJUSTMENT', 'LOADEXCEPTION-NOSCAN')
-- 2. NOSCAN 조건 충족 AND (NVL(t.useynbarcode,'Y') = 'N' OR NVL(t.barcodescan, 'N') = 'Y')
where -- 1. ADJUST 쪽 먼저 제외 NVL(t.adjust, 'NORMAL') NOT IN ('ADJUSTMENT', 'LOADEXCEPTION-NOSCAN') -- 2. NOSCAN 조건 제외 AND NOT (t.useynbarcode = 'N' OR NVL(t.barcodescan, 'N') = 'Y')
ORDER BY t.LOCATION, t.ITEMCODE, t.BARCODE

SELECT t.*, ROW_NUMBER() OVER (ORDER BY t.location, t.itemcode, t.barcode) AS rn FROM ( SELECT l.sdate, l.factory, l.storage, l.location, l.barcode, l.itemcode, l.qty, i.spec as oitemcode, i.itemname, l.useyn, L.YMDHMS_D, B.CUSTCODE, (SELECT USEYN FROM T_WMS_LOCATION LL WHERE L.IID = LL.IID) AS useynnow, (SELECT memo_d FROM T_WMS_LOCATION LL WHERE L.IID = LL.IID) AS adjust, (SELECT DISTINCT 'Y' FROM T_WMS_REALSTOCK RR WHERE L.BARCODE = RR.BARCODE AND SDATE>=#{startdate}
AND SUBSTR(RR.YMDHMS, 9, 2) >= #{hour}
AND SUBSTR(RR.YMDHMS, 9, 2) <= #{hour}
) AS BARCODESCAN, nvl((SELECT distinct USEYN FROM T_WMS_LOCATION LL WHERE L.iid = LL.iid and useyn ='Y'),'N') AS useynbarcode -- 260427 이부장님과 이야기후 barcode에서 iid로 변경 FROM t_wms_locationBACKUP l LEFT JOIN t_wms_realstock r ON r.useyn = 'Y' AND r.barcode = l.barcode
AND SUBSTR(R.YMDHMS, 9, 2) >= #{hour}
AND SUBSTR(R.YMDHMS, 9, 2) <= #{hour}
left join t_mi_item i on i.itemcode = l.itemcode LEFT JOIN T_MI_ITEM_CUSTINFO B ON L.ITEMCODE = B.ITEMCODE WHERE
1=1
AND B.CUSTCODE = #{custcode}
AND r.location IS NULL ) t
where NOT ( -- ✅ COMPLETE 조건 전체를 부정 NVL(t.adjust, 'NORMAL') NOT IN ('ADJUSTMENT', 'LOADEXCEPTION-NOSCAN') AND ( NVL(t.useynbarcode,'Y') = 'N' OR NVL(t.barcodescan, 'N') = 'Y' ) )
where t.adjust = 'ADJUSTMENT' OR T.ADJUST = 'LOADEXCEPTION-NOSCAN'
where -- 1. ADJUST 쪽 먼저 제외 NVL(t.adjust, 'NORMAL') NOT IN ('ADJUSTMENT', 'LOADEXCEPTION-NOSCAN')
-- 2. NOSCAN 조건 충족 AND (NVL(t.useynbarcode,'Y') = 'N' OR NVL(t.barcodescan, 'N') = 'Y')
where -- 1. ADJUST 쪽 먼저 제외 NVL(t.adjust, 'NORMAL') NOT IN ('ADJUSTMENT', 'LOADEXCEPTION-NOSCAN') -- 2. NOSCAN 조건 제외 AND NOT (t.useynbarcode = 'N' OR NVL(t.barcodescan, 'N') = 'Y')
ORDER BY t.LOCATION, t.ITEMCODE, t.BARCODE

SELECT NVL(SUM(qty_real), 0) as totalQty_real, NVL(COUNT(CASE WHEN qty_real > 0 THEN 1 END), 0) as totalCount_real, NVL(SUM(qty_system), 0) as totalQty_system, NVL(COUNT(CASE WHEN qty_system > 0 THEN 1 END), 0) as totalCount_system FROM ( SELECT r.qty_sum as qty_real, a.qty_sum as qty_system FROM ( SELECT a.sdate, a.location, a.factory, a.storage, c1.subname_ch as car, a.itemcode, a_item.itemname, SUM(a.qty) as qty_sum, COUNT(*) as qty_cnt FROM t_wms_stock a LEFT OUTER JOIN t_mi_item a_item ON a.itemcode = a_item.itemcode LEFT OUTER JOIN t_mi_typesub c1 ON a_item.carno = c1.subcode AND c1.typecode = 'MI041' WHERE
a.sdate = #{startdate}
a.sdate = TO_CHAR(SYSDATE, 'YYYY-MM-DD')
GROUP BY a.sdate, a.location, c1.subname_ch, a.itemcode, a_item.itemname,a.factory, a.storage ) a FULL OUTER JOIN ( SELECT r.sdate, r.location, r.factory, r.storage, c2.subname_ch as car, r.itemcode, r_item.itemname, SUM(r.qty) as qty_sum, COUNT(*) as qty_cnt FROM t_wms_realstock r LEFT OUTER JOIN t_mi_item r_item ON r.itemcode = r_item.itemcode LEFT OUTER JOIN t_mi_typesub c2 ON r_item.carno = c2.subcode AND c2.typecode = 'MI041' WHERE
r.sdate = #{startdate}
r.sdate = TO_CHAR(SYSDATE, 'YYYY-MM-DD')
GROUP BY r.sdate, r.location, c2.subname_ch, r.itemcode, r_item.itemname,r.factory, r.storage ) r ON a.sdate = r.sdate AND a.location = r.location AND a.itemcode = r.itemcode WHERE 1=1
)

SELECT * FROM ( SELECT t.*, ROW_NUMBER() OVER (ORDER BY sdate desc, barcode) AS rn FROM ( SELECT a.factory, a.storage, a.sdate, a.barcode, a.itemcode, a.qty, NVL(s.scanqty, 0) AS unpacked_qty, a.qty - NVL(s.scanqty, 0) AS diff_qty FROM t_wms_unpack a LEFT JOIN ( SELECT unpackbarcode, SUM(qty) AS scanqty FROM t_scm_barcode WHERE useyn = 'Y' GROUP BY unpackbarcode ) s ON s.unpackbarcode = a.barcode WHERE a.useyn = 'Y'
AND a.qty - NVL(s.scanqty, 0) <> 0
) t ) WHERE rn BETWEEN #{offset} + 1 AND #{offset} + #{itemsPerPage} ORDER BY rn

SELECT SUM( CASE WHEN REGEXP_LIKE(qty, '^[0-9]+(\.[0-9]+)?$') THEN TO_NUMBER(qty) ELSE 0 END ) AS total_qty, COUNT( CASE WHEN REGEXP_LIKE(qty, '^[0-9]+(\.[0-9]+)?$') THEN qty END ) AS count_qty FROM t_wms_semiwork WHERE useyn = 'Y'
AND sdate = #{sdate}
AND UPPER(TRIM(factory)) = UPPER(TRIM(#{factory}))

